```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace soft_delete_records {

struct Document {
  sqlgen::PrimaryKey<int> doc_id;
  std::string title;
  int is_deleted = 0;
  std::optional<sqlgen::DateTime> deleted_at;
};

bool soft_delete_records(const std::vector<int>& ids) {
    using namespace sqlgen::literals;

    // Connect to the database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        return false;
    }
    auto conn = conn_result.value();

    // Start transaction for atomicity
    auto transaction_result = conn->begin_transaction();
    if (!transaction_result) {
        return false;
    }

    try {
        // Iterate through each document ID and perform the update
        for (auto id : ids) {
            // Create update statement using sqlgen::update
            auto update_stmt = sqlgen::update<Document>(
                "is_deleted"_c.set(1),
                "deleted_at"_c.set(sqlgen::CURRENT_TIMESTAMP)
            ) | sqlgen::where("doc_id"_c == id);

            // Execute the update
            auto result = update_stmt(conn);
            if (!result) {
                // Rollback transaction if any update fails
                conn->rollback();
                return false;
            }
        }

        // Commit transaction if all updates succeed
        return conn->commit().value_or(false);

    } catch (...) {
        // Ensure rollback on exception
        conn->rollback();
        return false;
    }
}

}  // namespace soft_delete_records
```

## Key Implementation Points:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to establish connection
2. **Transaction Management**: Wraps updates in a transaction using `begin_transaction()`, `commit()`, and `rollback()`
3. **Batch Updates**: Iterates through each document ID and performs individual updates (as sqlgen prefers this approach over IN clauses)
4. **Update Construction**: Uses `sqlgen::update<Document>()` with `set()` method to update both `is_deleted` and `deleted_at` fields
5. **Current Timestamp**: Uses `sqlgen::CURRENT_TIMESTAMP` to set the deletion timestamp
6. **Where Clause**: Uses `sqlgen::where()` with equality condition to target specific document IDs
7. **Error Handling**: Properly handles errors and ensures transaction rollback on failure

The implementation follows sqlgen best practices by using the fluent API with the `|` operator to chain update statements with where conditions, and ensures data consistency through proper transaction management.

