bool upsert_inventory_items(const std::vector<Inventory>& items) {
  // Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false; // Connection failed
  }
  auto conn = *conn_result;

  // Perform upsert operation using write with or_replace=true
  auto write_result = sqlgen::write(conn, items, true);
  if (!write_result) {
    return false; // Write operation failed
  }

  // Read back the items to verify upsert behavior
  auto read_result = sqlgen::read<std::vector<Inventory>>(conn);
  if (!read_result) {
    return false; // Read operation failed
  }

  // Verify that the number of items matches (basic verification)
  if (read_result->size() != items.size()) {
    return false; // Item count mismatch
  }

  // Additional verification: check that all items have valid primary keys
  for (const auto& item : *read_result) {
    if (item.item_id.value() <= 0) {
      return false; // Invalid primary key value
    }
  }

  return true; // All operations succeeded
}

}  // namespace upsert_inventory_items
