```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <algorithm>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::optional<std::string> city;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
  int mutual_friends_count;
};

std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen::literals;

  // Create database connection
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Create tables using sqlgen's transpilation features
  auto create_users = sqlgen::create_table<User> | sqlgen::if_not_exists;
  auto create_friendships = sqlgen::create_table<Friendship> | sqlgen::if_not_exists;

  // Insert data
  auto insert_users = sqlgen::insert(users);
  auto insert_friendships = sqlgen::insert(friendships);

  // Build and execute queries

  // 1. Mutual friends using SELF-JOIN
  auto mutual_friends_query = 
      sqlgen::select_from<User, "u1">("username"_t1, "username"_t2, sqlgen::count("user_id2"_t3))
      | sqlgen::inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t3)
      | sqlgen::inner_join<Friendship, "f2">("user_id2"_t3 == "user_id1"_t4)
      | sqlgen::inner_join<User, "u2">("user_id2"_t4 == "user_id"_t2)
      | sqlgen::where("user_id"_t1 < "user_id"_t2)
      | sqlgen::group_by("user_id"_t1, "user_id"_t2)
      | sqlgen::having(sqlgen::count("user_id2"_t3) > 0);

  // 2. Users with more than average friends using nested query
  auto avg_friends_subquery = 
      sqlgen::select_from<Friendship, "f")(sqlgen::avg(sqlgen::count("user_id2"_t2)).as("avg_friends"))
      | sqlgen::group_by("user_id1"_t2);

  auto above_avg_friends_query = 
      sqlgen::select_from<User, "u">(sqlgen::count("user_id2"_t1).as("friend_count"))
      | sqlgen::left_join<Friendship, "f">("user_id"_t2 == "user_id1"_t1)
      | sqlgen::where(sqlgen::count("user_id2"_t1) > sqlgen::subquery(avg_friends_subquery))
      | sqlgen::group_by("user_id"_t2);

  // 3. Friend-of-friend relationships
  auto friend_of_friend_query = 
      sqlgen::select_from<User, "u1">("username"_t1, "username"_t3)
      | sqlgen::inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t2)
      | sqlgen::inner_join<Friendship, "f2">("user_id2"_t2 == "user_id1"_t3)
      | sqlgen::inner_join<User, "u2">("user_id2"_t3 == "user_id"_t3)
      | sqlgen::where(sqlgen::count_distinct("user_id2"_t2) == 1)
      | sqlgen::group_by("user_id"_t1, "user_id"_t3);

  // 4. Most connected users
  auto most_connected_users_query = 
      sqlgen::select_from<User, "u">(sqlgen::count("user_id2"_t1).as("friend_count"))
      | sqlgen::left_join<Friendship, "f">("user_id"_t2 == "user_id1"_t1)
      | sqlgen::order_by(sqlgen::count("user_id2"_t1).desc())
      | sqlgen::limit(10);

  // 5. Same city recommendations
  auto city_recommendations_query = 
      sqlgen::select_from<User, "u1">("username"_t1, "username"_t2)
      | sqlgen::inner_join<User, "u2">("city"_t1 == "city"_t2 && "user_id"_t1 != "user_id"_t2)
      | sqlgen::left_join<Friendship, "f">(("user_id1"_t3 == "user_id"_t1 && "user_id2"_t3 == "user_id"_t2) || 
                                           ("user_id1"_t3 == "user_id"_t2 && "user_id2"_t3 == "user_id"_t1))
      | sqlgen::where("friend_id"_t3.is_null());

  // Execute all queries
  auto mutual_results = mutual_friends_query(conn);
  auto above_avg_results = above_avg_friends_query(conn);
  auto friend_of_friend_results = friend_of_friend_query(conn);
  auto most_connected_results = most_connected_users_query(conn);
  auto recommendations_results = city_recommendations_query(conn);

  // Convert results to FriendConnection format
  std::vector<FriendConnection> results;

  // Process mutual friends
  for (const auto& row : mutual_results) {
    results.push_back(FriendConnection{
        .user1_name = row.template get_field<0>(),
        .user2_name = row.template get_field<1>(),
        .mutual_friends_count = row.template get_field<2>()
    });
  }

  // Process friend-of-friend relationships
  for (const auto& row : friend_of_friend_results) {
    results.push_back(FriendConnection{
        .user1_name = row.template get_field<0>(),
        .user2_name = row.template get_field<1>(),
        .mutual_friends_count = 1
    });
  }

  // Process city recommendations
  for (const auto& row : recommendations_results) {
    results.push_back(FriendConnection{
        .user1_name = row.template get_field<0>(),
        .user2_name = row.template get_field<1>(),
        .mutual_friends_count = 0
    });
  }

  return results;
}

}  // namespace analyze_social_network
```

