    // 4. Read items with quantity > 50, ordered by quantity descending
    auto read_result = (sqlgen::read<std::vector<Inventory>> 
                       | sqlgen::where("quantity"_c > 50) 
                       | sqlgen::order_by("quantity"_c.desc()))(conn);

    // 5. Verify at least one item is found and return true
    if (read_result && !read_result->empty()) {
        return true;
    }

    return false;
}

}  // namespace inventory_bulk_write_and_read
