 * description: update_set_operations.
 * This function demonstrates how to use set operations in update statements using sqlgen write API.
 * It returns true if the update operations are successful, and false otherwise.
 * Returns: bool.
 */
bool update_set_operations() {
  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = *conn_result;

  // 2. Create the Account table
  auto create_table_result = conn->execute(
      "CREATE TABLE IF NOT EXISTS Account ("
      "account_id INTEGER PRIMARY KEY, "
      "balance REAL, "
      "status TEXT)"
  );
  if (!create_table_result) {
    return false;
  }

  // 3. Use write API to insert initial data
  std::vector<Account> initial_data = {
    {1, 1000.0, "active"},
    {2, 2000.0, "inactive"},
    {3, 1500.0, "active"}
  };

  auto write_result = sqlgen::write(initial_data)(conn);
  if (!write_result) {
    return false;
  }

  // 4. Use update API with set operations to update balances and statuses
  // Update account 1: set balance to 1200.0 and status to "pending"
  auto update_stmt = sqlgen::update<Account>(
    "balance"_c.set(1200.0),
    "status"_c.set("pending")
  ) | sqlgen::where("account_id"_c == 1);

  auto update_result = update_stmt(conn);
  if (!update_result) {
    return false;
  }

  // Update account 2: set balance to balance + 500.0 (using arithmetic operation)
  auto update_stmt2 = sqlgen::update<Account>(
    "balance"_c.set("balance"_c + 500.0)
  ) | sqlgen::where("account_id"_c == 2);

  auto update_result2 = update_stmt2(conn);
  if (!update_result2) {
    return false;
  }

  // 5. Read the updated data to verify changes
  auto read_result = sqlgen::read<std::vector<Account>>(conn);
  if (!read_result) {
    return false;
  }

  auto updated_accounts = *read_result;

  // Verify specific updates
  bool verification_passed = true;

  // Check account 1 update
  auto account1 = std::find_if(updated_accounts.begin(), updated_accounts.end(),
                               [](const Account& acc) { return acc.account_id == 1; });
  if (account1 != updated_accounts.end() && 
      account1->balance == 1200.0 && 
      account1->status == "pending") {
    // Account 1 verified
  } else {
    verification_passed = false;
  }

  // Check account 2 update (balance should be 2500.0)
  auto account2 = std::find_if(updated_accounts.begin(), updated_accounts.end(),
                               [](const Account& acc) { return acc.account_id == 2; });
  if (account2 != updated_accounts.end() && 
      account2->balance == 2500.0) {
    // Account 2 verified
  } else {
    verification_passed = false;
  }

  // Check account 3 (should remain unchanged)
  auto account3 = std::find_if(updated_accounts.begin(), updated_accounts.end(),
