  if (account3 != updated_accounts.end() && 
      account3->balance == 1500.0 && 
      account3->status == "active") {
    // Account 3 verified
  } else {
    verification_passed = false;
  }

  return verification_passed;
}

}  // namespace update_set_operations
```

