JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen::literals;

  // 1. Connect to SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // 2. Create tables
  auto create_dept = conn.execute(R"(
    CREATE TABLE IF NOT EXISTS Department (
      department_id INTEGER PRIMARY KEY,
      department_name TEXT NOT NULL,
      location TEXT
    )
  )");

  auto create_emp = conn.execute(R"(
    CREATE TABLE IF NOT EXISTS Employee (
      employee_id INTEGER PRIMARY KEY,
      department_id INTEGER,
      first_name TEXT NOT NULL,
      last_name TEXT NOT NULL,
      salary REAL NOT NULL,
      FOREIGN KEY (department_id) REFERENCES Department(department_id)
    )
  )");

  // 3. Insert data
  auto insert_depts = conn.insert(depts.begin(), depts.end());
  auto insert_emps = conn.insert(emps.begin(), emps.end());

  // 4. Perform INNER JOIN
  auto inner_query = sqlgen::select_from<Department, "d">(
      "department_name"_t1 | sqlgen::as<"department_name">,
      "first_name"_t2 | sqlgen::as<"first_name">,
      "last_name"_t2 | sqlgen::as<"last_name">,
      "salary"_t2 | sqlgen::as<"salary">
  ).inner_join<Employee, "e">("department_id"_t1 == "department_id"_t2);

  auto inner_results = conn.read<std::vector<JoinResult>>(inner_query).value();

  // 5. Perform LEFT JOIN
  auto left_query = sqlgen::select_from<Employee, "e">(
      "first_name"_t2 | sqlgen::as<"first_name">,
      "last_name"_t2 | sqlgen::as<"last_name">,
      "salary"_t2 | sqlgen::as<"salary">,
      "department_name"_t1 | sqlgen::as<"department_name">
  ).left_join<Department, "d">("department_id"_t2 == "department_id"_t1);

  auto left_results = conn.read<std::vector<JoinResult>>(left_query).value();

  // 6. Perform RIGHT JOIN
  auto right_query = sqlgen::select_from<Department, "d">(
      "department_name"_t1 | sqlgen::as<"department_name">,
      "first_name"_t2 | sqlgen::as<"first_name">,
      "last_name"_t2 | sqlgen::as<"last_name">,
      "salary"_t2 | sqlgen::as<"salary">
  ).right_join<Employee, "e">("department_id"_t1 == "department_id"_t2);

  auto right_results = conn.read<std::vector<JoinResult>>(right_query).value();

  // 7. Perform FULL JOIN
  auto full_query = sqlgen::select_from<Department, "d">(
      "department_name"_t1 | sqlgen::as<"department_name">,
      "first_name"_t2 | sqlgen::as<"first_name">,
      "last_name"_t2 | sqlgen::as<"last_name">,
      "salary"_t2 | sqlgen::as<"salary">
  ).full_join<Employee, "e">("department_id"_t1 == "department_id"_t2);

  auto full_results = conn.read<std::vector<JoinResult>>(full_query).value();

  // 8. Return comprehensive analysis
  return JoinAnalysis{
      .inner_join_results = std::move(inner_results),
      .left_join_results = std::move(left_results),
      .right_join_results = std::move(right_results),
      .full_join_results = std::move(full_results)
  };
}
}  // namespace analyze_department_employees
```

## Key Implementation Details:

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish connection to "test_db.sqlite"

2. **Table Creation**: Creates Department and Employee tables with proper schema based on the provided table structures

3. **Data Insertion**: Uses `conn.insert()` to populate the tables with the provided vectors

4. **Join Operations**:
   - **INNER JOIN**: Uses `inner_join()` to get employees with assigned departments
   - **LEFT JOIN**: Uses `left_join()` to include all employees (even without departments)
   - **RIGHT JOIN**: Uses `right_join()` to include all departments (even without employees)
   - **FULL JOIN**: Uses `full_join()` to include all records from both tables

5. **Query Construction**: Uses sqlgen's fluent API with table aliases ("d" for Department, "e" for Employee) and column selection with proper aliasing using `sqlgen::as<>`

6. **Result Handling**: Uses `conn.read<std::vector<JoinResult>>()` to execute queries and map results to the `JoinResult` structure

7. **Error Handling**: Uses `.value()` to extract results from `Result` types, throwing exceptions on failure

The implementation follows sqlgen's principles of using a fluent, type-safe API for database operations while maintaining the comprehensive analysis requirements specified in the assessment objectives.

